package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringWriter;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreSurroundingSpaces() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat newCsvFormat = csvFormat.withIgnoreSurroundingSpaces(true);

        // Then
        assertFalse(csvFormat.getIgnoreSurroundingSpaces());
        assertTrue(newCsvFormat.getIgnoreSurroundingSpaces());
    }

    @Test
    public void testWithIgnoreSurroundingSpaces_false() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat newCsvFormat = csvFormat.withIgnoreSurroundingSpaces(false);

        // Then
        assertFalse(newCsvFormat.getIgnoreSurroundingSpaces());
    }

    @Test
    public void testWithIgnoreSurroundingSpaces_usingReflection() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat newCsvFormat = invokeWithIgnoreSurroundingSpaces(csvFormat, true);

        // Then
        assertFalse(csvFormat.getIgnoreSurroundingSpaces());
        assertTrue(newCsvFormat.getIgnoreSurroundingSpaces());
    }

    private CSVFormat invokeWithIgnoreSurroundingSpaces(CSVFormat csvFormat, boolean ignoreSurroundingSpaces)
            throws Exception {
        java.lang.reflect.Method method = CSVFormat.class.getDeclaredMethod("withIgnoreSurroundingSpaces", boolean.class);
        method.setAccessible(true);
        return (CSVFormat) method.invoke(csvFormat, ignoreSurroundingSpaces);
    }
}
